5	error_t ec_pve_batch_t::encrypt(const pve_base_pke_i& base_pke, pve_keyref_t ek, mem_t label, ecurve_t curve,
6	                                const std::vector<bn_t>& _x) {
7	  error_t rv = UNINITIALIZED_ERROR;
8	  cb_assert(n > 0 && n <= MAX_BATCH_COUNT);
9	  cb_assert(int(_x.size()) == n);
10	
11	  const mod_t& q = curve.order();
12	  const auto& G = curve.generator();
13	  int curve_size = curve.size();
14	  std::vector<bn_t> x(n);
15	
16	  for (int j = 0; j < n; j++) {
17	    x[j] = _x[j] % q;
18	    Q[j] = x[j] * G;
19	  }
20	
21	  buf128_t r01[kappa], r02[kappa];
22	  buf128_t r1[kappa];
23	  buf_t c0[kappa];
24	  buf_t c1[kappa];
25	  std::vector<ecc_point_t> X0[kappa];
26	  std::vector<ecc_point_t> X1[kappa];
27	  L = buf_t(label);
28	  buf_t inner_label = genPVELabelWithPoint(label, Q);
29	
30	  for (int i = 0; i < kappa; i++) {
31	    X0[i].resize(n);
32	    X1[i].resize(n);
33	
34	    crypto::gen_random(r01[i]);
35	    crypto::gen_random(r02[i]);
36	    crypto::gen_random(r1[i]);
37	    crypto::drbg_aes_ctr_t drbg01(r01[i]);
38	    crypto::drbg_aes_ctr_t drbg02(r02[i]);
39	    crypto::drbg_aes_ctr_t drbg1(r1[i]);
40	
41	    buf_t x0_source_bin = drbg01.gen(n * (curve_size + coinbase::bits_to_bytes(SEC_P_STAT)));
42	    buf_t rho0 = drbg02.gen(rho_size);
43	    buf_t rho1 = drbg1.gen(rho_size);
44	
45	    std::vector<bn_t> x0;
46	    if (rv = bn_t::vector_from_bin(x0_source_bin, n, curve_size + coinbase::bits_to_bytes(SEC_P_STAT), q, x0))
47	      return rv;
48	    std::vector<bn_t> x1(n);
49	    for (int j = 0; j < n; j++) {
50	      MODULO(q) x1[j] = x[j] - x0[j];
51	
52	      X0[i][j] = x0[j] * G;
53	      X1[i][j] = Q[j] - X0[i][j];
54	    }
55	
56	    buf_t x1_bin = bn_t::vector_to_bin(x1, curve_size);
57	
58	    if (rv = base_pke.encrypt(ek, inner_label, r01[i], rho0, c0[i])) return rv;
59	    if (rv = base_pke.encrypt(ek, inner_label, x1_bin, rho1, c1[i])) return rv;
60	    rows[i].x_bin = x1_bin;  // some of these will be reset to zero later based on `bi`
61	  }
62	
63	  b = crypto::ro::hash_string(Q, label, c0, c1, X0, X1).bitlen(kappa);
64	
65	  for (int i = 0; i < kappa; i++) {
66	    bool bi = b.get_bit(i);
67	    rows[i].r = bi ? r1[i] : (r01[i] + r02[i]);
68	    rows[i].c = bi ? c0[i] : c1[i];
69	    if (!bi) rows[i].x_bin.free();
70	  }
71	  return SUCCESS;
72	}
